// =============================================================
// Save Input Payload — audit per attempt (T-209)
// =============================================================
// Save responseId + field_mapping + resolved updates BEFORE
// Supabase PATCH. Mirrors the resolution logic in the patch node
// to capture the actual values that will be written.
// =============================================================

// @inline env-supabase-preamble
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
// @end-inline env-supabase-preamble

// @inline supabase-request
async function supabaseRequest(path, method, body, opts) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const prefer = (opts && opts.prefer) || 'return=representation';
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': prefer,
      },
    };
    const req = https.request(options, (res) => {
      // UTF-8 boundary safety: without setEncoding, chunks are Buffers and
      // `data += chunk` does an implicit chunk.toString() PER chunk. When a
      // multi-byte UTF-8 character (e.g. 'ł' = 0xC5 0x82) straddles a chunk
      // boundary, each half decodes to U+FFFD (replacement char). setEncoding
      // makes Node buffer internally and emit string chunks only at character
      // boundaries — concat-safe for any UTF-8 payload.
      res.setEncoding('utf8');
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

function resolveExpression(expression, context) {
  if (typeof expression !== 'string') return expression;
  const match = expression.match(/^\{\{\s*([\w.]+)\s*\}\}$/);
  if (match) {
    const key = match[1].trim();
    const parts = key.split('.');
    let value = context;
    for (const part of parts) {
      if (value === null || value === undefined || typeof value !== 'object') return expression;
      value = value[part];
    }
    return value !== undefined ? value : expression;
  }
  return expression;
}

const item = $input.first().json;
const { variableContext, currentStep, tenantId } = item;
const responseId = (variableContext && variableContext.responseId) ?? null;
const fieldMapping = (currentStep && currentStep.step_config && currentStep.step_config.field_mapping) || [];

// Resolve updates so audit captures what will be written
const updates = {};
if (Array.isArray(fieldMapping)) {
  for (const mapping of fieldMapping) {
    if (!mapping || !mapping.target_column) continue;
    updates[mapping.target_column] = resolveExpression(mapping.source_expression, variableContext);
  }
}

const inputPayload = {
  responseId,
  mapping: fieldMapping,
  updates,
  tenant_id: tenantId,
};

if (item.currentStepExecId) {
  await supabaseRequest(
    `workflow_step_executions?id=eq.${item.currentStepExecId}`,
    'PATCH',
    { input_payload: inputPayload }
  );
}

return { json: item };

// =============================================================
// Update Response Handler — PATCH responses row with field_mapping
// =============================================================
// Reads variableContext.responseId and currentStep.step_config.field_mapping.
// Resolves source_expression against variableContext (simple {{stepId.fieldKey}} pattern).
// PATCHes responses table via Supabase REST.
// JSONB columns (ai_qualification): pass object directly — NEVER JSON.stringify (double-encode bug).
// tenant_id filter on all Supabase queries for security.
// =============================================================

// @inline env-supabase-preamble
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL environment variable not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
// @end-inline env-supabase-preamble

// Simple {{key}} and {{nested.key}} variable resolver against variableContext
function resolveExpression(expression, context) {
  if (typeof expression !== 'string') return expression;
  // Handle {{variable}} pattern
  const match = expression.match(/^\{\{\s*([\w.]+)\s*\}\}$/);
  if (match) {
    const key = match[1].trim();
    // Support nested paths like stepId.fieldKey
    const parts = key.split('.');
    let value = context;
    for (const part of parts) {
      if (value === null || value === undefined || typeof value !== 'object') return expression;
      value = value[part];
    }
    return value !== undefined ? value : expression;
  }
  // Plain string (no template) — return as-is
  return expression;
}

// @inline supabase-request
async function supabaseRequest(path, method, body, opts) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const prefer = (opts && opts.prefer) || 'return=representation';
    const options = {
      hostname: match[1],
      path: match[2],
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': prefer,
      },
    };
    const req = https.request(options, (res) => {
      // UTF-8 boundary safety: without setEncoding, chunks are Buffers and
      // `data += chunk` does an implicit chunk.toString() PER chunk. When a
      // multi-byte UTF-8 character (e.g. 'ł' = 0xC5 0x82) straddles a chunk
      // boundary, each half decodes to U+FFFD (replacement char). setEncoding
      // makes Node buffer internally and emit string chunks only at character
      // boundaries — concat-safe for any UTF-8 payload.
      res.setEncoding('utf8');
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase ${method || 'GET'} ${path} ${res.statusCode}: ${data}`));
          return;
        }
        try {
          resolve(data ? JSON.parse(data) : null);
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body !== undefined && body !== null) req.write(JSON.stringify(body));
    req.end();
  });
}
// @end-inline supabase-request

// @inline supabase-crud
async function supabaseGet(table, filterOrParams, value, select) {
  let qs;
  if (typeof filterOrParams === 'string') {
    const p = new URLSearchParams();
    p.append(filterOrParams, `eq.${value}`);
    if (select) p.append('select', select);
    p.append('limit', '1');
    qs = p.toString();
  } else {
    qs = new URLSearchParams(filterOrParams).toString();
  }
  return supabaseRequest(`${table}?${qs}`, 'GET');
}

async function supabasePatch(path, body, opts) {
  return supabaseRequest(path, 'PATCH', body, opts);
}
// @end-inline supabase-crud

try {
  const item = $input.first().json;
  const { variableContext, currentStep, tenantId } = item;

  // Validate required input
  const responseId = variableContext.responseId;
  if (!responseId) throw new Error('update_response requires variableContext.responseId');

  const fieldMapping = (currentStep && currentStep.step_config && currentStep.step_config.field_mapping) || [];
  if (!Array.isArray(fieldMapping) || fieldMapping.length === 0) {
    // No mappings configured — succeed with no-op
    return {
      json: {
        ...item,
        stepResult: {
          success: true,
          outputPayload: { updated: true, updatedAt: new Date().toISOString() },
        },
      }
    };
  }

  const safeTenantId = tenantId ?? '00000000-0000-0000-0000-000000000000';

  // Build PATCH body from resolved field_mapping
  const patchBody = {};
  for (const mapping of fieldMapping) {
    const { target_column, source_expression } = mapping;
    if (!target_column) continue;
    const resolved = resolveExpression(source_expression, variableContext);
    // JSONB columns: pass object directly — never JSON.stringify (double-encode bug)
    patchBody[target_column] = resolved;
  }

  // PATCH responses with tenant_id filter for security
  await supabasePatch(
    `responses?id=eq.${responseId}&tenant_id=eq.${encodeURIComponent(safeTenantId)}`,
    patchBody,
    { prefer: 'return=minimal' }
  );

  return {
    json: {
      ...item,
      stepResult: {
        success: true,
        outputPayload: { updated: true, updatedAt: new Date().toISOString() },
      },
    }
  };
} catch (err) {
  const item = $input.first().json;
  return { json: { ...item, stepResult: { success: false, error: err.message } } };
}
